#include <stdio.h>
#include <math.h>
#include <inttypes.h>

static __int128 ipow(__int128 a, int k, __int128 limit) {
    __int128 res = 1;
    while (k) {
        if (k & 1) {
            if (res > limit / a) return limit + 1; // overflow detection
            res *= a;
        }
        k >>= 1;
        if (k) {
            if (a > limit / a) a = limit + 1; else a *= a;
        }
    }
    return res;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned long long n; scanf("%llu", &n);
        __int128 best = -1; unsigned long long ans = 0; unsigned long long diff = (unsigned long long)(-1);
        for(int k=2;k<=60;k++){
            double nd = (double)n;
            unsigned long long a = (unsigned long long)pow(nd, 1.0/k);
            if(a==0) a=1;
            // adjust a to be floor root
            while(ipow(a+1, k, (__int128)n) <= (__int128)n) ++a;
            while(ipow(a, k, (__int128)n) > (__int128)n) --a;
            for(unsigned long long candBase = a; candBase <= a+1; ++candBase){
                if(candBase==0) continue;
                __int128 val = ipow(candBase, k, (__int128)18446744073709551615ULL);
                if(val> (__int128)1000000000000000000ULL) continue;
                unsigned long long v = (unsigned long long)val;
                unsigned long long d = n>v? n-v : v-n;
                if(best==-1 || d<diff || (d==diff && v<ans)){
                    best = val; ans = v; diff = d;
                }
            }
        }
        // also consider 1 explicitly (already covered when a becomes 1)
        printf("%llu\n", ans);
    }
    return 0;
}

