import java.io.*;
import java.util.*;

public class Main {
    static final long LIMIT = 1_000_000_000_000_000_000L; // 1e18
    static long powLimit(long a, int k, long limit) {
        long res = 1;
        while (k > 0) {
            if ((k & 1) == 1) {
                if (a != 0 && res > limit / a) return limit + 1;
                res *= a;
            }
            k >>= 1;
            if (k > 0) {
                if (a != 0 && a > limit / a) a = limit + 1; else a *= a;
            }
        }
        return res;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            long n = Long.parseLong(br.readLine().trim());
            long best = 0;
            long bestDiff = Long.MAX_VALUE;
            for (int k = 2; k <= 60; k++) {
                double nd = (double) n;
                long a = (long) Math.pow(nd, 1.0 / k);
                if (a < 1) a = 1;
                while (powLimit(a + 1, k, LIMIT) <= n) a++;
                while (powLimit(a, k, LIMIT) > n) a--;
                for (long base = a; base <= a + 1; base++) {
                    if (base < 1) continue;
                    long val = powLimit(base, k, LIMIT);
                    if (val > LIMIT) continue;
                    long diff = Math.abs(n - val);
                    if (diff < bestDiff || (diff == bestDiff && val < best)) {
                        bestDiff = diff;
                        best = val;
                    }
                }
            }
            out.append(best).append('\n');
        }
        System.out.print(out.toString());
    }
}

