import sys, math
LIMIT = 10**18

def ipow(a, k, limit):
    res = 1
    while k:
        if k & 1:
            if a != 0 and res > limit // a:
                return limit + 1
            res *= a
        k >>= 1
        if k:
            if a != 0 and a > limit // a:
                a = limit + 1
            else:
                a *= a
    return res

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        best = 0
        best_diff = 10**20
        for k in range(2, 61):
            a = int(pow(n, 1.0 / k))
            if a < 1:
                a = 1
            while ipow(a + 1, k, LIMIT) <= n:
                a += 1
            while ipow(a, k, LIMIT) > n:
                a -= 1
            for base in (a, a + 1):
                if base < 1:
                    continue
                val = ipow(base, k, LIMIT)
                if val > LIMIT:
                    continue
                diff = abs(n - val)
                if diff < best_diff or (diff == best_diff and val < best):
                    best_diff = diff
                    best = val
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

