  while (exp > 0) {
    if (exp & 1) {
      if (base !== 0n && res > limit / base) return limit + 1n;
      res *= base;
    }
    exp >>= 1;
    if (exp) {
      if (base !== 0n && base > limit / base) base = limit + 1n; else base *= base;
